package pl.msurvival.ranks;import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.configuration.file.*;import org.bukkit.entity.*;import org.bukkit.event.*;import org.bukkit.event.player.*;import org.bukkit.plugin.java.JavaPlugin;import org.bukkit.scoreboard.*;import java.io.*;import java.util.*;public final class MSurvivalRanks extends JavaPlugin implements Listener{private File f;private YamlConfiguration data;public void onEnable(){saveDefaultConfig();f=new File(getDataFolder(),"players.yml");if(!f.exists())try{getDataFolder().mkdirs();f.createNewFile();}catch(Exception e){e.printStackTrace();}data=YamlConfiguration.loadConfiguration(f);Bukkit.getPluginManager().registerEvents(this,this);Bukkit.getScheduler().runTaskTimer(this,()->Bukkit.getOnlinePlayers().forEach(this::apply),20L,100L);}public boolean onCommand(CommandSender s,Command c,String l,String[] a){if(c.getName().equalsIgnoreCase("setrank")){if(!s.hasPermission("msurvival.ranks.admin")){s.sendMessage(msg("no-permission"));return true;}if(a.length<2)return true;String r=a[1].toLowerCase(Locale.ROOT);if(!getConfig().contains("ranks."+r)){s.sendMessage(color("&cNie ma rangi."));return true;}data.set("players."+a[0].toLowerCase(Locale.ROOT),r);save();Player t=Bukkit.getPlayerExact(a[0]);if(t!=null)apply(t);return true;}if(c.getName().equalsIgnoreCase("rank")&&s instanceof Player p){p.sendMessage(color("&7Twoja ranga: "+display(rank(p))));}return true;}@EventHandler public void join(PlayerJoinEvent e){Bukkit.getScheduler().runTaskLater(this,()->apply(e.getPlayer()),20L);}@EventHandler public void chat(AsyncPlayerChatEvent e){e.setFormat(color(prefix(rank(e.getPlayer()))+"%1$s &8» &f%2$s").replace("%","%%"));}private void apply(Player p){String r=rank(p);p.setPlayerListName(color(prefix(r)+p.getName()));side(p);}private void side(Player p){if(!getConfig().getBoolean("sidebar.enabled",true))return;Scoreboard b=Bukkit.getScoreboardManager().getNewScoreboard();Objective o=b.registerNewObjective("msr","dummy",color(getConfig().getString("sidebar.title")));o.setDisplaySlot(DisplaySlot.SIDEBAR);int sc=getConfig().getStringList("sidebar.lines").size();Set<String> used=new HashSet<>();for(String raw:getConfig().getStringList("sidebar.lines")){String line=color(raw.replace("%player%",p.getName()).replace("%rank%",display(rank(p))).replace("%online%",String.valueOf(Bukkit.getOnlinePlayers().size())).replace("%ping%",String.valueOf(p.getPing())));while(used.contains(line))line+=ChatColor.RESET;used.add(line);o.getScore(line.length()>40?line.substring(0,40):line).setScore(sc--);}p.setScoreboard(b);}private String rank(Player p){return data.getString("players."+p.getName().toLowerCase(Locale.ROOT),"gracz");}private String display(String r){return color(getConfig().getString("ranks."+r+".display",r));}private String prefix(String r){return getConfig().getString("ranks."+r+".prefix","&7GRACZ &7");}private void save(){try{data.save(f);}catch(Exception e){e.printStackTrace();}}private String msg(String k){return color(getConfig().getString("messages.prefix","")+getConfig().getString("messages."+k,""));}private String color(String t){return ChatColor.translateAlternateColorCodes('&',t==null?"":t);}}
